using System.ComponentModel;
using Microsoft.Extensions.Logging;
using ModelContextProtocol.Server;

/// <summary>
/// MCP tool that calls an external API via HttpClient injected through DI.
/// </summary>
[McpServerToolType]
public class ApiTools(HttpClient httpClient, ILogger<ApiTools> logger)
{
    [McpServerTool, Description("Fetch data from an external API endpoint and return the response body.")]
    public async Task<string> FetchApi(
        [Description("The full URL of the API endpoint to call (e.g. https://api.example.com/data)")] string url,
        CancellationToken cancellationToken = default)
    {
        logger.LogInformation("Fetching API: {Url}", url);

        using var response = await httpClient.GetAsync(url, cancellationToken);
        response.EnsureSuccessStatusCode();

        var body = await response.Content.ReadAsStringAsync(cancellationToken);
        logger.LogInformation("Received {Length} characters from {Url}", body.Length, url);

        return body;
    }
}

