using System.ComponentModel;
using Microsoft.Extensions.AI;
using ModelContextProtocol.Server;

/// <summary>
/// MCP prompt templates for summarization tasks.
/// </summary>
[McpServerPromptType]
public static class SummarizationPrompts
{
    [McpServerPrompt, Description("Summarize the provided content into a concise paragraph.")]
    public static ChatMessage Summarize(
        [Description("The text content to summarize")] string content) =>
        new(ChatRole.User, $"Summarize the following content into a concise paragraph:\n\n{content}");

    [McpServerPrompt, Description("Summarize the provided content as a bullet-point list of key takeaways.")]
    public static ChatMessage SummarizeAsBullets(
        [Description("The text content to extract key points from")] string content) =>
        new(ChatRole.User, $"Extract the key takeaways from the following content and present them as a bullet-point list:\n\n{content}");
}

